import { throwParseError } from "@ark/util"
import type { JsonSchemaOrBoolean, Type } from "arktype"
import {
	writeJsonSchemaRefInvalidFormatMessage,
	writeJsonSchemaRefUnresolvableMessage
} from "./errors.ts"
import { jsonSchemaToType } from "./json.ts"

interface JsonSchemaDefsFrame {
	defs: Record<string, JsonSchemaOrBoolean>
	cache: Map<string, Type.Any>
}

const defsFrames: JsonSchemaDefsFrame[] = []

export const pushJsonSchemaDefsFrame = (
	defs: Record<string, JsonSchemaOrBoolean>
): void => {
	defsFrames.push({ defs, cache: new Map() })
}

export const popJsonSchemaDefsFrame = (): void => {
	defsFrames.pop()
}

const jsonSchemaRefPattern = /^#\/\$defs\/([^/]+)$/

export const resolveJsonSchemaRef = (ref: string): Type.Any => {
	const match = jsonSchemaRefPattern.exec(ref)
	if (!match) throwParseError(writeJsonSchemaRefInvalidFormatMessage())

	const name = match[1]

	for (let i = defsFrames.length - 1; i >= 0; i--) {
		const frame = defsFrames[i]
		if (!(name in frame.defs)) continue

		const cached = frame.cache.get(name)
		if (cached) return cached

		// register a lazily-resolving alias before parsing the definition's body
		// so that a $ref cycle (direct or indirect recursion) resolves to this
		// same node rather than reparsing indefinitely
