		const cyclicAlias = node("alias", {
			reference: `jsonSchema$defs.${name}`,
			resolve: () => resolvedInternal!
		}) as unknown as Type.Any
		frame.cache.set(name, cyclicAlias)

		const resolved = jsonSchemaToType(frame.defs[name])
		resolvedInternal = resolved.internal
		// once fully resolved, prefer the concrete type over the alias for any
		// future (non-cyclic) reference so composition (e.g. anyOf) isn't forced
		// to deal with an unresolved node
		frame.cache.set(name, resolved)

		return resolved
	}

	throwParseError(writeJsonSchemaRefUnresolvableMessage(ref))
}
