import { printable } from "@ark/util"
import { type, type JsonSchema, type Type } from "arktype"
import { jsonSchemaToType } from "./json.ts"

export const parseIfThenElseJsonSchema = (
	jsonSchema: JsonSchema
): Type | undefined => {
	if (!("if" in jsonSchema) || jsonSchema.if === undefined) return undefined

	const ifValidator = jsonSchemaToType(jsonSchema.if)
	const thenValidator =
		"then" in jsonSchema && jsonSchema.then !== undefined ?
			jsonSchemaToType(jsonSchema.then)
		:	undefined
	const elseValidator =
		"else" in jsonSchema && jsonSchema.else !== undefined ?
			jsonSchemaToType(jsonSchema.else)
		:	undefined

	// an 'if' with neither 'then' nor 'else' is a no-op that imposes no constraints
	if (!thenValidator && !elseValidator) return undefined

	const jsonSchemaIfThenElseValidator = (data: unknown, ctx: Traversal) => {
		if (ifValidator.allows(data)) {
			if (thenValidator && !thenValidator.allows(data)) {
				return ctx.reject({
					expected: `valid according to 'then' schema: ${thenValidator.description}, since 'if' schema matched`,
					actual: printable(data)
				})
			}
		} else if (elseValidator && !elseValidator.allows(data)) {
			return ctx.reject({
				expected: `valid according to 'else' schema: ${elseValidator.description}, since 'if' schema did not match`,
				actual: printable(data)
			})
		}
		return true
	}
	return type.unknown.narrow(jsonSchemaIfThenElseValidator)
}
