					:	ctx.reject({
							expected: resolved.description,
							actual: printable(data)
						})
			}
			return type.unknown.narrow(jsonSchemaCyclicRefValidator)
		}

		frame.inProgress.add(name)
		try {
			const resolved = jsonSchemaToType(frame.defs[name])
			frame.cache.set(name, resolved)
			return resolved
		} finally {
			frame.inProgress.delete(name)
		}
	}

	throwParseError(writeJsonSchemaRefUnresolvableMessage(ref))
}
